/* Compute the highest node degree in the undirected graph. The graph is defined in the adjacency
   matrix A.  A is an NxN adjacency matrix stored in row-major order.  The function preserves
   the exact semantics of the reference implementation while exploiting parallelization
   and cache‑friendly access patterns. */
inline int maxDegree(std::vector<int> const& A, std::size_t N)
{
    // Pointer access removes bounds checks and is cache friendly.
    const int *a = A.data();

    int highestDegree = 0;

    // Parallelize over rows: each thread computes a local maximum and the
    // compiler merges them with a reduction. The inner loop is kept simple
    // and unrolled by the compiler.
#pragma omp parallel for reduction(max : highestDegree)
    for (std::size_t i = 0; i < N; ++i) {
        int degree = 0;
        const int *row = a + i * N;
        for (std::size_t j = 0; j < N; ++j) {
            degree += row[j];
        }
        if (degree > highestDegree) highestDegree = degree;
    }

    return highestDegree;
}
