#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/* Return the logical XOR reduction of the vector of bools x.
   Example:
   input: [false, false, false, true]
   output: true
*/
inline bool reduceLogicalXOR(std::vector<bool> const& x) {
    // Process the vector in blocks of 64 bits for maximum speed.
    // We use a parallel reduction courtesy of OpenMP.
    std::uint64_t local = 0;
    const std::size_t n = x.size();
    const size_t block = 64;          // 64 bits per word

    #pragma omp parallel reduction(^ : local)
    {
        std::uint64_t word = 0;
        std::size_t idx;

        #pragma omp for schedule(static)
        for (idx = 0; idx + block <= n; idx += block) {
            word = 0;
            for (size_t j = 0; j < block; ++j) {
                word = (word << 1) | (x[idx + j] ? 1ULL : 0ULL);
            }
            local ^= word;
        }

        // Handle any remaining bits that don't fit into a full block
        #pragma omp for schedule(static)
        for (; idx < n; ++idx) {
            local ^= static_cast<std::uint64_t>(x[idx]);
        }
    }

    // Count set bits in the final XORed word and return true if odd.
    return __builtin_popcountll(local) & 1;
}
