#pragma once
#include <vector>
#include <cstddef>
#include <limits>
#include <algorithm>

/* Return the length of the shortest path from source to dest in the undirected graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major. The graph is connected and undirected.
*/
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Fast access to matrix data
    const int* mat = A.data();

    // Use a simple FIFO queue implemented on a vector to avoid pair/queue overhead
    std::vector<int> queue(N);
    size_t head = 0, tail = 0;
    queue[tail++] = source;

    // distance array initialized to -1 (unvisited)
    std::vector<int> dist(N, -1);
    dist[source] = 0;

    while (head < tail) {
        int u = queue[head++];
        int d = dist[u];
        if (u == dest) return d;                    // early exit

        // Iterate over all neighbours of u
        const int* row = mat + u * N;
        for (size_t v = 0; v < N; ++v) {
            if (row[v] && dist[v] == -1) {
                dist[v] = d + 1;
                queue[tail++] = static_cast<int>(v);
            }
        }
    }

    // The graph is assumed to be connected; return max int if unreachable
    return std::numeric_limits<int>::max();
}
