30_scan_prefix_sum:
```cpp
#pragma once
#include <vector>
#include <cstdint>
#include <omp.h>
#include <numeric>

/* Compute the prefix sum of the vector x into output.
   Example:
   input:  [1, 7, 4, 6, 6, 2]
   output: [1, 8, 12, 18, 24, 26]          */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    const int n_threads = omp_get_max_threads();
    const std::size_t block = (n + n_threads - 1) / n_threads;      // ceil

    /* 1) each thread computes local prefix and a block sum */
    std::vector<int64_t> block_sums(n_threads, 0);

#pragma omp parallel
    {
        const int tid     = omp_get_thread_num();
        const std::size_t first = tid * block;
        const std::size_t last  = std::min(first + block, n);
        if (first >= last) return;        // empty block

        int64_t sum = 0;
        for (std::size_t i = first; i < last; ++i) {
            sum += x[i];
            output[i] = sum;              // local prefix
        }
        block_sums[tid] = sum;
    }

    /* 2) build prefix of block sums */
    std::vector<int64_t> block_prefix(n_threads, 0);
    for (int i = 1; i < n_threads; ++i)
        block_prefix[i] = block_prefix[i-1] + block_sums[i-1];

    /* 3) add block prefix to each element */
#pragma omp parallel for schedule(static, block)
    for (std::size_t i = 0; i < n; ++i) {
        const int tid = i / block;
        output[i] += block_prefix[tid];
    }
}
