    std::fill(bins.begin(), bins.end(), 0);

    // Work per thread: a local array that is accumulated at the end.
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 10>> local(nthreads);
    for (int t = 0; t < nthreads; ++t)
        local[t].fill(0);

