    {
        const int tid = omp_get_thread_num();
        const std::size_t* ptr = x.data();
        const std::size_t N   = x.size();

        // Process in a single loop; the division is by an integer literal.
        // Use size_t for indices so that the compiler can optimize.
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < N; ++i) {
            const std::size_t bin = static_cast<std::size_t>(ptr[i] / 10.0);
            // `bin` is guaranteed to be in [0,9] because the input range is [0,100].
            local[tid][bin] += 1;
        }
