#pragma once
#include <vector>
#include <unordered_map>
#include <algorithm>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute Y = A * X with A (MxK) and X (KxN) in COO format.
 * Y is a dense MxN matrix stored in row-major order.
 * The implementation builds a per‑row index of X and then
 * parallelises over the A non‑zeros using OpenMP reduction.
 */
void spmm(const std::vector<COOElement>& A,
          const std::vector<COOElement>& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N)
{
    // Initialise output matrix with zeros
    Y.assign(M * N, 0.0);

    /* 1. Build an index from X.row to the list of non‑zeros
     *    in that row.  This reduces the inner search from O(K)
     *    to O(#nonzeros in the row).
     */
    std::vector<std::vector<COOElement>> x_rows(K);
    for (const auto& e : X) {
        // Assume values are valid: 0 <= e.row < K
        x_rows[e.row].push_back(e);
    }

    /* 2. Parallel multiplication.
     *    The outer loop over A non‑zeros is embarrassingly parallel.
     *    We use atomic updates on Y because different A entries may
     *    contribute to the same Y position.
     *    A read‑only per‑row index of X guarantees work locality.
     */
#pragma omp parallel for schedule(dynamic)
    for (size_t ai = 0; ai < A.size(); ++ai) {
        const auto& a = A[ai];
        if (a.column >= K) continue;          // safety check
        const auto& x_row = x_rows[a.column];
        for (const auto& x : x_row) {
            // Compute the flat index only once
