/*
 * Count the number of cartesian points in each quadrant.
 * Results are accumulated in bins[4] as follows:
 *   bins[0] – Q1: x >= 0 && y >= 0
 *   bins[1] – Q2: x <  0 && y >= 0
 *   bins[2] – Q3: x <  0 && y <  0
 *   bins[3] – Q4: x >= 0 && y <  0
 *
 * Implementation uses OpenMP parallel reduction and avoids
 * expensive branches by converting the quadrant test to an
 * unsigned integer mask.
 */
inline void countQuadrants(std::vector<Point> const& points,
                           std::array<std::size_t, 4>& bins)
{
    // Zero the output array first
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    const std::size_t n = points.size();

    // Pre-allocate thread-local bins to avoid contention
    #pragma omp parallel
    {
        std::array<std::size_t, 4> local = {0, 0, 0, 0};

        #pragma omp for nowait
        for (std::size_t i = 0; i < n; ++i)
        {
            const double x = points[i].x;
            const double y = points[i].y;

            // Use unsigned comparisons to eliminate branches:
            //  ux = x < 0  (bit 1)
            //  uy = y < 0  (bit 2)
            const unsigned int ux = static_cast<unsigned int>(x < 0.0);
            const unsigned int uy = static_cast<unsigned int>(y < 0.0);
            const unsigned int mask = (ux << 1) | uy; // 0..3

            // Fast indexed increment
            local[mask] += 1;
        }

        // Combine local results into the global bins
        #pragma omp atomic update
        bins[0] += local[0];
        #pragma omp atomic update
        bins[1] += local[1];
        #pragma omp atomic update
        bins[2] += local[2];
        #pragma omp atomic update
        bins[3] += local[3];
    }
}
