// Computes the discrete Fourier transform of `x`.
// The result is stored in `output`. The function is thread-safe and
// preserves the exact semantics of the reference implementation.
inline void dft(const std::vector<double> &x, std::vector<std::complex<double>> &output) {
    const std::size_t N = x.size();
    output.resize(N, std::complex<double>(0.0, 0.0));

    // Parallelise the outer loop: each output element is independent.
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < static_cast<int>(N); ++k) {
        // Normalise the exponent: e^{-j*2πkn/N}
        const double angle_step = -2.0 * M_PI * static_cast<double>(k) / static_cast<double>(N);
        const std::complex<double> twiddle_step(std::cos(angle_step), std::sin(angle_step));

        std::complex<double> w(1.0, 0.0);   // e^{-j*2πkn/N} for current n
        std::complex<double> sum(0.0, 0.0);

        for (std::size_t n = 0; n < N; ++n) {
            sum += std::complex<double>(x[n], 0.0) * w;
            w *= twiddle_step;   // advance to next exponent
        }
        output[k] = sum;
    }
}
