```cpp
#pragma once
#include <vector>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Dense LU factorization: A = L * U
 * A is provided in COO format.  L and U are returned as flat N×N
 * row‑major vectors.  The implementation uses cache‑friendly
 * blocking and OpenMP parallelism.
 *
 * The algorithm is identical to the sequential one in the
 * original code; no pivoting is performed.
 */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 size_t N)
{
    /* Allocate dense storage for A (temporary) */
    std::vector<double> fullA(N * N, 0.0);
    for (auto const& e : A)
        fullA[e.row * N + e.column] = e.value;

    /* Initialize L to zero (diagonal later set to 1) */
    L.assign(N * N, 0.0);
    /* U will be built on the fly, but allocating it early lets us
       keep a row-major layout and avoid reallocations. */
    U.assign(N * N, 0.0);

    /* Block LU – choose a block size that fits in L2/L3 cache
       (~32–64 KB).  For 8 threads a 32‑block is a good compromise. */
    const int BLOCK = 32;
    for (size_t i = 0; i < N; ++i) {
        /* U[i, j] for j >= i  – compute row i of U */
        #pragma omp parallel for schedule(static, BLOCK)
        for (size_t j = i; j < N; ++j) {
            double acc = fullA[i * N + j];
            for (size_t k = 0; k < i; ++k)
                acc -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = acc;
        }

        /* L[i, j] for j < i  – compute column i of L */
        #pragma omp parallel for schedule(static, BLOCK)
        for (size_t j = 0; j < i; ++j) {
            double acc = fullA[i * N + j];
            for (size_t k = 0; k < j; ++k)
                acc -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = acc / U[j * N + j];
        }

        /* Set the diagonal of L to 1 */
        L[i * N + i] = 1.0;
    }
}
