/*
 * Count the number of pixels in image with each grayscale intensity.
 * The vector `image` is a grayscale image with values 0-255.
 * Store the results in `bins`.
 * Example:
 *
 *   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
 *   output: [0, 0, 2, 0, 1, ...]
 */
void pixelCounts(std::vector<int> const& image, std::array<size_t, 256> &bins) {
    // initialise the output histogram to zero
    std::fill(bins.begin(), bins.end(), 0);

    // source array pointer for fast indexing
    const int* restrict src = image.data();
    const std::size_t n = image.size();

    /* Parallel per‑thread histograms: each thread keeps its own copy
     * of 256 counts.  The number of threads is limited to at most 64
     * (good for 8‑thread cores while still leaving space for cache),
     * but we leave the default OpenMP choice intact.
     */
    int const max_threads = omp_get_max_threads();
    std::vector<std::array<size_t, 256>> local(max_threads);

    #pragma omp parallel
    {
        int const tid   = omp_get_thread_num();
        int const stride = (n + max_threads - 1) / max_threads;
        std::size_t start = static_cast<std::size_t>(tid) * stride;
        std::size_t end   = std::min(start + stride, n);

        // local histogram for this thread
        std::array<size_t, 256> &hist = local[tid];
        hist.fill(0);

        /* Simple loop unrolling (4‑way) to make better use of the
         * memory subsystem and to reduce loop‑overhead.  The values
         * are guaranteed to be in [0,255] so no bounds check is needed.
         */
        std::size_t i = start;
        for (; i + 4 <= end; i += 4) {
            ++hist[src[i]];
            ++hist[src[i + 1]];
            ++hist[src[i + 2]];
            ++hist[src[i + 3]];
        }
        for (; i < end; ++i) {
            ++hist[src[i]];
        }
    } // end parallel

    /* Reduce per‑thread histograms into the final result. */
    for (int t = 0; t < max_threads; ++t) {
        for (int v = 0; v < 256; ++v) {
            bins[v] += local[t][v];
        }
    }
}
