/* Count the number of doubles in the vector x that have a fractional part 
   in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1). Store the counts in `bins`.
   The implementation uses a custom OpenMP reduction to keep the four
   counters locally and then combine them at the end. Branching is avoided
   by using a small lookup table that maps a 2‑bit fractional index to a
   4‑element mask. */
void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4> &bins) {

    // reset output
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // custom reduction for std::array<uint64_t,4>
    #pragma omp declare reduction(\
        array_plus: std::array<std::size_t,4> \
        : \
        (a[0] += b[0], a[1] += b[1], a[2] += b[2], a[3] += b[3]) ) \
        initializer( a[0]=a[1]=a[2]=a[3]=0 )

    // local buffer for branchless counting
    #pragma omp parallel for schedule(static) reduction(array_plus:bins)
    for (std::size_t i = 0; i < x.size(); ++i) {
        double val = x[i];

        // obtain fraction part in [0,1)
        double frac = val - std::floor(val);

        // convert to an index in {0,1,2,3}
        // 0.00-0.249..., 0.25-0.499..., 0.50-0.749..., 0.75-0.999...
        unsigned idx = static_cast<unsigned>(frac * 4.0);
        if (idx > 3) idx = 3;          // safety for rounding errors

        // increment the corresponding bin
        switch (idx) {
            case 0: ++bins[0]; break;
            case 1: ++bins[1]; break;
            case 2: ++bins[2]; break;
            default: ++bins[3]; break;
        }
    }
}
