/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
        (implementation is equivalent to the original O(n²) version)
*/
double closestPair(std::vector<double> const& x) {
    // The vector needs to have at least two elements
    if (x.size() < 2) {
        return 0.0;
    }

    // Work on a copy to avoid modifying the caller's data
    std::vector<double> sorted(x.begin(), x.end());
    std::sort(sorted.begin(), sorted.end());  // O(n log n)

    double minDist = std::numeric_limits<double>::max();

    // Only adjacent pairs can be the closest after sorting
    for (std::size_t i = 0; i + 1 < sorted.size(); ++i) {
        const double d = std::abs(sorted[i + 1] - sorted[i]);
        if (d < minDist) {
            minDist = d;
            // Early exit: can't get smaller than 0
            if (minDist == 0.0) break;
        }
    }

    return minDist;
}
