/* Compute one iteration of a 3‑point 1D Jacobi stencil.
   output[i] = (input[i‑1] + input[i] + input[i+1]) / 3
   where out‑of‑bounds neighbours are treated as zero. */
inline void jacobi1D(const std::vector<double>& input, std::vector<double>& output) noexcept
{
