    if (n == 0) return;        // nothing to do

    const double*   inp = input.data();
          double*   out = output.data();

    /* Parallelise the main loop.  A static schedule works well
       because the work per iteration is identical. */
#pragma omp parallel for schedule(static) default(none) shared(inp, out, n)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i)
    {
        double sum = inp[i];                    // centre element

        if (i > 0)          sum += inp[i - 1]; // left neighbour
        if (i + 1 < static_cast<std::ptrdiff_t>(n))
            sum += inp[i + 1];    // right neighbour

        out[i] = sum / 3.0;
    }
