// --------------  Optimised iterative radix‑2 FFT -----------------
static inline void fft(std::vector<std::complex<double>> const& x,
                       std::vector<std::complex<double>>& out)
{
    const size_t N = x.size();
    out = x;                       // make a copy
    if (N <= 1) return;

    // --- bit‑reverse reorder -------------------------------------------------
    size_t log2N = 0;
    for (size_t tmp = N; tmp > 1; tmp >>= 1, ++log2N) {}
    size_t rev = 0, mask;
    for (size_t i = 0; i < N; ++i)
    {
        if (i < rev) std::swap(out[i], out[rev]);

        mask = N >> 1;
        while (rev & mask) { rev ^= mask; mask >>= 1; }
        rev ^= mask;
    }

    // --- iterative butterfly --------------------------------------------------
    std::complex<double> w_m(1.0, 0.0);
    for (size_t s = 1; s <= log2N; ++s)
    {
        size_t m = 1ULL << s;              // current block size
        size_t m2 = m >> 1;                // half block
        double theta = -M_PI / m2;
        std::complex<double> w( std::cos(theta), std::sin(theta) );

        // compute w_m = w^(m/2) once per stage
        w_m = std::pow(w, m2);

        // stride = block size
        size_t stride = m;

        // ----- parallel outer loop: each thread processes distinct block pairs ----
#ifdef _OPENMP
#pragma omp parallel for schedule(static)
#endif
        for (size_t k = 0; k < N; k += stride)
        {
            std::complex<double> w_k(1.0, 0.0);
            for (size_t j = 0; j < m2; ++j)
            {
                std::complex<double> t = w_k * out[k + j + m2];
                std::complex<double> u = out[k + j];
                out[k + j] = u + t;
                out[k + j + m2] = u - t;
                w_k *= w;
            }
        }
    }
}
