#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

/*
 * Optimised in‑place radix‑2 Cooley–Tukey FFT.
 * The algorithm uses iterative butterflies and
 * precalculated twiddle factors.
 *
 * The function signature is kept exactly as the original
 * so that the harness can call it unchanged.
 */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<double> &r,
                std::vector<double> &i)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    /* -----------------------------
     * 1. Prepare data
     * ----------------------------- */
    std::vector<std::complex<double>> a(x);   // copy of input

    /* Bit‑reversal permutation */
    std::size_t m = static_cast<std::size_t>(std::log2(N));
    for (std::size_t i1 = 0; i1 < N; ++i1) {
        std::size_t rev = 0;
        std::size_t tmp = i1;
        for (std::size_t j = 0; j < m; ++j) {
            rev = (rev << 1) | (tmp & 1);
            tmp >>= 1;
        }
        if (rev > i1) std::swap(a[i1], a[rev]);
    }

    /* Pre‑compute twiddle factors:
     *  w[n] = exp(-2πi n / N)
     * We need only one row per stage, so store in a flat vector.
     */
    std::vector<std::complex<double>> twiddles(N/2);
    for (std::size_t k = 1; k < N/2; ++k) {
        double angle = -2.0 * M_PI * k / static_cast<double>(N);
        twiddles[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    /* -----------------------------
     * 2. Butterfly stages
     * ----------------------------- */
    std::size_t step = 1;
#pragma omp parallel for schedule(static)
    for (std::size_t stage = 0; stage < m; ++stage) {
        std::size_t jump = step << 1;   // 2*step
        std::size_t offset = 0;
        for (std::size_t group = 0; group < N; group += jump) {
            for (std::size_t j = 0; j < step; ++j) {
                std::complex<double> t = a[group + j] + a[group + j + step];
                std::complex<double> u = a[group + j] - a[group + j + step];
                std::size_t idx = offset + j;
                a[group + j] = t;
                a[group + j + step] = u * twiddles[idx];
            }
            offset += step;
        }
        step = jump;
    }

    /* -----------------------------
     * 3. Split into real/imag parts
     * ----------------------------- */
#pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
