    const std::size_t rowSize = N;
    const std::size_t lastRow = N - 1;
    const std::size_t lastCol = N - 1;

    // Parallelise over the two outer dimensions.
    // OpenMP collapses the two loops into a single dynamic range to
    // avoid thread imbalance when N is small.
