            // Up neighbour
            if (i != 0 && in[(i - 1) * rowSize + j] == 1) ++count;
            // Down neighbour
            if (i != lastRow && in[(i + 1) * rowSize + j] == 1) ++count;
            // Left neighbour
            if (j != 0 && in[i * rowSize + j - 1] == 1) ++count;
            // Right neighbour
            if (j != lastCol && in[i * rowSize + j + 1] == 1) ++count;

            out[i * rowSize + j] = (count == 1) ? 1 : 0;
        }
    }
}
