/* Return the index of the value in the vector x that is closest to the math constant PI
   Use M_PI for the value of PI. */
size_t findClosestToPi(std::vector<double> const& x) {
    // Handle empty vector – behavior undefined in original, but guard anyway
    if (x.empty()) return std::numeric_limits<size_t>::max();

    const double pi = M_PI;
    size_t bestIndex = 0;
    double bestDiff = std::fabs(x[0] - pi);

    // Parallel reduction over index and minimum difference
    #pragma omp parallel for reduction(minimum:bestDiff, bestIndex)
    {
        // Custom reduction: track best for each thread, then combine
        struct local_t { double diff; size_t idx; };
        local_t local{bestDiff, bestIndex};

        for (size_t i = std::max<size_t>(1, omp_get_thread_num());
             i < x.size();
             i += omp_get_num_threads()) {
            double d = std::fabs(x[i] - pi);
            if (d < local.diff) {
                local.diff = d;
                local.idx  = i;
            }
        }

        // Reduce local results into shared variables
        #pragma omp critical
        {
            if (local.diff < bestDiff) {
                bestDiff  = local.diff;
                bestIndex = local.idx;
            }
        }
    }

    return bestIndex;
}
