#include <omp.h>

/* Optimised GEMM implementation
 * A : MxK matrix, B : KxN matrix, C : MxN matrix (row-major).
 * Accumulates into C (C += A*B).
 */
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    /* Block sizes tuned for an 8‑core Xeon with
     * ~5–10 KiB L1 data cache per core and 32 KiB L2 cache. */
    constexpr size_t BLOCK_M = 64;
    constexpr size_t BLOCK_K = 64;
    constexpr size_t BLOCK_N = 64;

    /* Simple pointer aliases for speed */
    const double *a = A.data();
    const double *b = B.data();
    double       *c = C.data();

    /* OpenMP parallelisation over outermost block of rows */
    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += BLOCK_M) {
        size_t i_max = std::min(i0 + BLOCK_M, M);
        for (size_t j0 = 0; j0 < N; j0 += BLOCK_N) {
            size_t j_max = std::min(j0 + BLOCK_N, N);
            for (size_t k0 = 0; k0 < K; k0 += BLOCK_K) {
                size_t k_max = std::min(k0 + BLOCK_K, K);

                /* L3 cache friendly triple loop order: i -> k -> j */
                for (size_t i = i0; i < i_max; ++i) {
                    const double *a_row = a + i*K;
                    double       *c_row = c + i*N;
                    for (size_t k = k0; k < k_max; ++k) {
                        double a_val = a_row[k];
                        const double *b_row = b + k*N;
                        for (size_t j = j0; j < j_max; ++j) {
                            c_row[j] += a_val * b_row[j];
                        }
                    }
                }
            }
        }
    }
}
