inline double cross(const Point& a, const Point& b, const Point& c) {
    /* Twice the signed area of triangle abc */
    return (a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));
}

static inline double absd(double v) {
    return v < 0.0 ? -v : v;
}

/*
 * Return the area of the smallest triangle that can be formed by any 3 points.
 * This implementation preserves the exact semantics of the original algorithm
 * while parallelising the triple nested loops with OpenMP.
 */
double smallestArea(const std::vector<Point>& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    /* Parallelise the outer two loops.  Each thread keeps a local best
       and the global reduction combines them at the end. */
    #pragma omp parallel for collapse(2) schedule(static) \
            reduction(min:minArea)
    for (size_t i = 0; i < n - 2; ++i) {
        for (size_t j = i + 1; j < n - 1; ++j) {
            const Point& pi = points[i];
            const Point& pj = points[j];
            for (size_t k = j + 1; k < n; ++k) {
                const double area = 0.5 * absd(cross(pi, pj, points[k]));
                if (area < minArea) {
                    minArea = area;
                }
            }
        }
    }
    return minArea;
}
