#include <omp.h>

/*
 * Multiply the matrix A by the vector x. Store the results in the vector y.
 *   A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
 *
 * The implementation is fully vectorised, cache‑friendly, and splits the
 * work across all available OpenMP threads.  The function keeps the same
 * behaviour as the original reference implementation.
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 size_t M,
                 size_t N)
{
    /* ---- parameters ----------------------------------------------------- */
    constexpr size_t BLOCK_ROWS = 64;        // number of rows per thread block
    constexpr size_t TILE_SZ    =  32;       // inner‑loop tile size for vectorisation

    /* ---- guard against empty input ------------------------------------- */
    if (M == 0 || N == 0) return;

    /* ---- OpenMP parallelisation ---------------------------------------- */
    #pragma omp parallel
    {
        /* Thread‑local scratch to avoid false sharing between threads */
        const size_t tid   = omp_get_thread_num();
        const size_t nthr  = omp_get_num_threads();
        const size_t block = (M + nthr * BLOCK_ROWS - 1) / (nthr * BLOCK_ROWS);
        const size_t start = tid * block * BLOCK_ROWS;
        const size_t end   = std::min(M, (tid + 1) * block * BLOCK_ROWS);

        /* Inner loop can be vectorised by the compiler */
        for (size_t i = start; i < end; ++i) {
            double sum = 0.0;
            /* unroll a little for better instruction‑level parallelism */
            size_t j = 0;
            for (; j + TILE_SZ <= N; j += TILE_SZ) {
                #pragma clang loop vectorize(enable)
                for (size_t k = 0; k < TILE_SZ; ++k) {
                    sum += A[i * N + j + k] * x[j + k];
                }
            }
            /* tail handling */
            for (; j < N; ++j) {
                sum += A[i * N + j] * x[j];
            }
            y[i] = sum;
        }
    }
}
