#pragma once
#include <vector>
#include <algorithm>
#include <unordered_set>

/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   Examples:
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=7
   output: true
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=1
   output: false
*/
inline bool xorContains(const std::vector<int>& x,
                        const std::vector<int>& y,
                        int val)
{
    // Find the smaller vector to build the hash set on
    const auto* small = &x;
    const auto* large = &y;
    if (x.size() > y.size()) {
        small = &y;
        large = &x;
    }

    // Build a hash set from the smaller vector
    std::unordered_set<int> seen;
    seen.reserve(small->size() * 2);
    for (int v : *small) {
        if (v == val)   // early exit if already found in the same vector
            return false;
        seen.insert(v);
    }

    // Scan the larger vector, stopping once we find `val`.
    bool found = false;
    for (int v : *large) {
        if (v == val) {
            found = true;
            break;
        }
    }

    // If `val` was found in both or neither, return false
    return found && !seen.count(val);
}
