struct Point {
    double x, y;
};

/* Compute the convex hull of a set of points.
 * The hull is returned in counter‑clockwise order starting from
 * the lowest‑leftmost point.
 */
inline double cross(const Point &a, const Point &b, const Point &c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point> &points, std::vector<Point> &hull) {
    const std::size_t n = points.size();
    if (n < 3) { hull = points; return; }

    /* --- 1. sort points by x, then y ------------------------------------ */
    std::vector<Point> pts = points;
#pragma omp parallel
    {
        std::size_t chunk = (n + omp_get_num_threads() - 1) / omp_get_num_threads();
        std::size_t start = omp_get_thread_num() * chunk;
        std::size_t end   = std::min(start + chunk, n);
        std::sort(pts.begin() + start, pts.begin() + end,
                  [](const Point &a, const Point &b) {
                      return (a.x < b.x) || (a.x == b.x && a.y < b.y);
                  });
    }
    std::sort(pts.begin(), pts.end(),
              [](const Point &a, const Point &b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    /* --- 2. build lower hull -------------------------------------------- */
    std::vector<Point> lower;
    lower.reserve(n);
    for (const auto &p : pts) {
        while (lower.size() >= 2 &&
               cross(lower[lower.size()-2], lower[lower.size()-1], p) <= 0)
            lower.pop_back();
        lower.push_back(p);
    }

    /* --- 3. build upper hull -------------------------------------------- */
    std::vector<Point> upper;
    upper.reserve(n);
    for (auto it = pts.rbegin(); it != pts.rend(); ++it) {
        while (upper.size() >= 2 &&
               cross(upper[upper.size()-2], upper[upper.size()-1], *it) <= 0)
            upper.pop_back();
        upper.push_back(*it);
    }

    /* --- 4. concatenate, removing duplicate endpoints ------------------- */
    hull.clear();
    hull.reserve(lower.size() + upper.size() - 2);
    hull.insert(hull.end(), lower.begin(), lower.end());
    hull.insert(hull.end(), upper.begin() + 1, upper.end() - 1);
}
