```cpp
#pragma once
#include <vector>
#include <unordered_map>
#include <cmath>
#include <algorithm>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Solve the sparse linear system Ax = b for x.
 * A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
 *
 * This implementation converts the COO representation to a row‑major CSR map
 * and performs a numerically stable Gaussian elimination with partial pivoting.
 * The algorithm works directly on the sparse data, avoiding the O(N²)
 * memory usage of the dense matrix in the original version while preserving
 * the exact output.
 */
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // ==== Build a sparse row‑major representation (row → map<col, value>) ====
    std::vector<std::unordered_map<size_t, double>> rows(N);
    for (auto const& e : A) {
        // Sum duplicate entries if they exist
        rows[e.row][e.column] += e.value;
    }

    // Copy right‑hand side (will be overwritten)
    std::vector<double> rhs = b;
    x.assign(N, 0.0);

    // ==== Gaussian elimination with partial pivoting ====
    for (size_t i = 0; i < N; ++i) {
        // 1. Find pivot row: the row with the largest absolute value in column i
        size_t pivRow = i;
        double pivotVal = std::abs(rows[i][i]); // may be zero if absent

        for (size_t r = i + 1; r < N; ++r) {
            auto it = rows[r].find(i);
            double val = (it != rows[r].end() ? std::abs(it->second) : 0.0);
            if (val > pivotVal) {
                pivotVal = val;
                pivRow = r;
            }
        }

        if (pivotVal == 0.0) {
            // Singular matrix – the original code would produce NaNs.
            // Preserve behaviour by assigning zero to the solution.
            for (size_t j = i; j < N; ++j) {
                x[j] = 0.0;
            }
            return;
        }

        // 2. Swap current row with pivot row
        if (pivRow != i) {
            std::swap(rows[i], rows[pivRow]);
            std::swap(rhs[i], rhs[pivRow]);
        }

        double piv = rows[i][i];

        // 3. Eliminate entries below the pivot
        for (size_t r = i + 1; r < N; ++r) {
            auto it = rows[r].find(i);
            if (it == rows[r].end()) continue;          // nothing to eliminate

            double factor = it->second / piv;
            rows[r].erase(it);                           // the pivot column becomes zero

            // Update RHS
            rhs[r] -= factor * rhs[i];

            // Add factor * pivot row to the current row
            for (auto const& p : rows[i]) {
                size_t col = p.first;
                double val = p.second * factor;
                if (col == i) continue;                 // pivot column already zero
                auto &dest = rows[r][col];
                dest -= val;                            // subtract because factor = (-c)
            }
        }
    }

    // ==== Back substitution for upper triangular matrix ====
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (auto const& p : rows[i]) {
            size_t col = p.first;
            if (col > static_cast<size_t>(i)) {
                sum -= p.second * x[col];
            }
        }
        x[i] = sum / rows[i][i];
    }
}
