/*
 * Compute the order statistics (i.e., ranks) of the values in `x`.  
 * The output `ranks_` contains for each index `i` the rank of
 * `x[i]` when all elements are sorted in ascending order.
 *
 * Example:
 *   x = [3.1, 2.8, 9.1, 0.4, 3.14]
 *   ranks_ = [2, 1, 4, 0, 3]
 *
 * The implementation builds an index vector, sorts it using a
 * lightweight comparator and then writes the ranks.  The sorting
 * itself is the performance bottleneck; the remainder of the
 * algorithm is linear and already very cheap.
 */
inline void ranks(const std::vector<float>& x, std::vector<std::size_t>& ranks_) {
    const std::size_t n = x.size();
    if (n == 0) return;

    // Pre‑allocate the rank vector once to avoid reallocations inside the harness
    ranks_.resize(n);

    // Build an index array [0,1,2,...,n-1]
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    // Sort indices according to the values in x
    // The inlined lambda is simple enough for GCC to optimise
    std::sort(idx.begin(), idx.end(),
              [&](std::size_t a, std::size_t b) noexcept { return x[a] < x[b]; });

    // Materialise the ranks (parallelised because it is fully data‑race free)
    #pragma omp parallel for if (n > 1 << 12) schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[idx[i]] = i;
    }
}
