#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>

struct Point
{
    double x, y;
};

// --------------------------------------------------------------------------
// Helper utilities – inlined for speed
// --------------------------------------------------------------------------
inline double sqr(double v) noexcept { return v * v; }

inline double dist(const Point& a, const Point& b) noexcept
{
    return std::hypot(b.x - a.x, b.y - a.y);   // fast sqrt of sum of squares
}

inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

// --------------------------------------------------------------------------
// Convex hull perimeter – O(n log n)
// --------------------------------------------------------------------------
double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;                         // fewer than 3 points → degenerate perimeter

    // 1. Copy & sort points lexicographically (x, then y)
    std::vector<Point> sorted(points.begin(), points.end());
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept
              {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // 2. Build hull with a single array
    std::vector<Point> hull(2 * n);   // maximum possible size
    std::size_t k = 0;                // current hull size

    // Lower hull
    for (std::size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    // Upper hull
    for (std::size_t i = n; i-- > 0;)
    {
        while (k >= 2 + (n - i) && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    // Final hull size is k - 1 (first point repeated at the end)
    hull.resize(k - 1);

    // 3. Sum distances around the hull
    double perimeter = 0.0;
#pragma omp parallel for reduction(+:perimeter) schedule(static)
    for (std::size_t i = 0; i + 1 < hull.size(); ++i)
        perimeter += dist(hull[i], hull[i + 1]);

    perimeter += dist(hull[0], hull.back());   // closing edge

    return perimeter;
}
