    const int* end = p + x.size();

    // C-style loop with pointer arithmetic and manual unrolling
    for (; p + 7 < end; p += 8) {
        if (p[0] % 2 == 0) return p - x.data();
        if (p[1] % 2 == 0) return p - x.data() + 1;
        if (p[2] % 2 == 0) return p - x.data() + 2;
        if (p[3] % 2 == 0) return p - x.data() + 3;
        if (p[4] % 2 == 0) return p - x.data() + 4;
        if (p[5] % 2 == 0) return p - x.data() + 5;
        if (p[6] % 2 == 0) return p - x.data() + 6;
        if (p[7] % 2 == 0) return p - x.data() + 7;
    }

    // Handle remaining elements
    for (; p < end; ++p) {
        if (*p % 2 == 0) return p - x.data();
    }
    return x.size();
