/*
   Sort the vector `x` of complex numbers by their magnitude in ascending order.
   The relative order of elements with equal magnitude is preserved (stable sort).
*/
void sortComplexByMagnitude(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N < 2) return;                      // already sorted

    // Step 1: compute magnitudes in parallel
    std::vector<double> mags(N);
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        mags[i] = std::norm(x[i]);          // norm = |z|^2, cheaper than abs

    // Step 2: create index vector and sort by magnitude
    std::vector<std::size_t> idx(N);
    for (std::size_t i = 0; i < N; ++i) idx[i] = i;

    std::sort(idx.begin(), idx.end(),
              [&](std::size_t a, std::size_t b) {
                  double da = mags[a], db = mags[b];
                  if (da < db) return true;
                  if (da > db) return false;
                  return a < b;              // stable tie‑break
              });

    // Step 3: reorder the original vector according to the sorted indices
    std::vector<std::complex<double>> tmp(N);
    for (std::size_t i = 0; i < N; ++i)
        tmp[i] = x[idx[i]];
    x.swap(tmp);
}
