#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * In‑place LU factorisation of an N×N matrix stored row‑major in A.
 *
 * For each pivot row k, the following is executed:
 *   - Compute the multipliers for rows i>k.
 *   - Update the remaining sub‑matrix.
 *
 * The algorithm is parallelised over the rows i of each pivot step,
 * exploiting the fact that every update of row i depends only on row k,
 * which is fully available before row i starts.
 * -------------------------------------------------------------
 *   A  – input matrix (modified in‑place to contain L and U)
 *   N  – dimension of the square matrix
 * -------------------------------------------------------------
 */
inline void luFactorize(std::vector<double> &A, size_t N) noexcept
{
    // Cache the stride to avoid repeated multiplication
    const std::size_t stride = N;

    for (std::size_t k = 0; k < N; ++k)
    {
        // Address of the pivot element
        const double *const pkRow = &A[k * stride + k];
        const double piv = *pkRow;

        // Parallelise the row updates for this pivot
#pragma omp parallel for schedule(static)
        for (std::size_t i = k + 1; i < N; ++i)
        {
            double *const iRow = &A[i * stride];
            const double *const kRow = &A[k * stride];

            // Compute the multiplier and store it in the L‑part
            const double factor = iRow[k] / piv;
            iRow[k] = factor;

            // Unrolled loop for better vectorisation
            std::size_t j = k + 1;
            // Process 4 elements at a time
            for (; j + 3 < N; j += 4)
            {
                const double a0 = kRow[j];
                const double a1 = kRow[j + 1];
                const double a2 = kRow[j + 2];
                const double a3 = kRow[j + 3];

                iRow[j]     -= factor * a0;
                iRow[j + 1] -= factor * a1;
                iRow[j + 2] -= factor * a2;
                iRow[j + 3] -= factor * a3;
            }
            // Tail handling
            for (; j < N; ++j)
                iRow[j] -= factor * kRow[j];
        }
    }
}
