#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:
   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
inline void solveLinearSystem(const std::vector<double>& A,
                              const std::vector<double>& b,
                              std::vector<double>& x,
                              size_t N)
{
    // Allocate temporary arrays once
    std::vector<double> A_copy(A);
    std::vector<double> b_copy(b);

    // Forward elimination
    for (size_t i = 0; i < N - 1; ++i) {
        const double pivot = A_copy[i * N + i];
        // If pivot is zero, the system is singular – we simply return.
        if (pivot == 0.0) return;

        const double inv_pivot = 1.0 / pivot;
#pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            const double factor = A_copy[j * N + i] * inv_pivot;
            const size_t row_j_offset = j * N;
            const size_t row_i_offset = i * N;
#pragma unroll 4
            for (size_t k = i; k < N; ++k) {
                A_copy[row_j_offset + k] -= factor * A_copy[row_i_offset + k];
            }
            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const size_t base = i * N;
#pragma omp simd reduction(+:sum)
        for (size_t j = i + 1; j < N; ++j) {
            sum += A_copy[base + j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / A_copy[base + i];
    }
}
