/// Find the k‑th smallest element of the vector `x`.
/// `k` is 1‑based; the function returns the same value as the original
/// (a sorted copy would return `x_copy[k-1]`).
int findKthSmallest(std::vector<int> const& x, int k)
{
    // Direct copy of the input (this is already cheap, no need for extra
    // parallelisation for typical use‑cases).  A simple `std::nth_element`
    // gives the correct result in linear expected time.
    std::vector<int> tmp = x;

    // Move the k‑th smallest element into its final position.
    std::nth_element(tmp.begin(), tmp.begin() + (k - 1), tmp.end());

    // The element is now at position k‑1.
    return tmp[k - 1];
}
