            size_t idx;
            #pragma omp atomic capture
            idx = pos++;
            nzIdx[idx] = i;
        }
    }

    // 3. Copy non‑zero values into a separate buffer and sort it
    std::vector<int> values(nonZeroCount);
    #pragma omp parallel for schedule(static)
    for (size_t k = 0; k < nonZeroCount; ++k) {
        values[k] = x[nzIdx[k]];
