    std::sort(values.begin(), values.end());   // fast enough on one thread

    // 4. Write sorted values back to their original positions
    #pragma omp parallel for schedule(static)
    for (size_t k = 0; k < nonZeroCount; ++k) {
        x[nzIdx[k]] = values[k];
    }
