/* ----------------------------------------------------
   Optimised radix‑2 Cooley–Tukey FFT
   ---------------------------------------------------- */
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const size_t N = x.size();
    if (N < 2) return;

    /* ----- Bit‑reverse permutation table ----- */
    static std::vector<size_t> rev;
    static size_t rev_n = 0;
    if (rev.size() != N)
    {
        rev.resize(N);
        const size_t m = static_cast<size_t>(std::log2(N));
        for (size_t i = 0; i < N; ++i)
        {
            size_t v = i;
            v = ((v & 0xaaaaaaaa) >> 1) | ((v & 0x55555555) << 1);
            v = ((v & 0xcccccccc) >> 2) | ((v & 0x33333333) << 2);
            v = ((v & 0xf0f0f0f0) >> 4) | ((v & 0x0f0f0f0f) << 4);
            v = ((v & 0xff00ff00) >> 8) | ((v & 0x00ff00ff) << 8);
            v = ((v >> 16) | (v << 16)) >> (32 - m);
            rev[i] = v;
        }
        rev_n = N;
    }

    /* ----- Bit‑reverse permutation ----- */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        size_t j = rev[i];
        if (j > i) std::swap(x[i], x[j]);
    }

    /* ----- Iterative radix‑2 FFT stages ----- */
    const double two_pi = 2.0 * M_PI;
    for (size_t offset = 1; offset < N; offset <<= 1)
    {
        const size_t step = offset << 1;
        const double theta = -two_pi / static_cast<double>(step);
        const std::complex<double> w_step(std::cos(theta), std::sin(theta));

        /* Butterfly loop – parallelisable over k */
        #pragma omp parallel for schedule(static)
        for (size_t k = 0; k < offset; ++k)
        {
            std::complex<double> w(1.0, 0.0);
            for (size_t j = k; j < N; j += step)
            {
                const size_t l = j + offset;
                const std::complex<double> t = w * x[l];
                x[l] = x[j] - t;
                x[j] += t;
                w *= w_step;
            }
        }
    }
}

/* ----------------------------------------------------
   Inverse FFT – conjugate, FFT, conjugate, scale
   ---------------------------------------------------- */
inline void ifft(std::vector<std::complex<double>>& x)
{
    std::transform(x.begin(), x.end(), x.begin(),
                   [](std::complex<double> v) { return std::conj(v); });

    fft_helper(x);

    std::transform(x.begin(), x.end(), x.begin(),
                   [](std::complex<double> v) { return std::conj(v); });

    const double inv_size = 1.0 / static_cast<double>(x.size());
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i)
        x[i] *= inv_size;
}
