/* Edge‑convolution kernel (fixed 3×3).  */
static constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/* ------------------------------------------------------------------ */
/* Perform the convolution.  Preserves the exact semantics of the
 * reference implementation (zero padding, clipping to [0,255]).
 *  ───────────────────────────────────────────────────────────────────
 *
 * @param imageIn   Input image (row‑major, NxN, grayscale).
 * @param imageOut  Output image (same dimensions as input).
 * @param N         Image dimension (NxN).
 *
 * Note: The function is fully parallelised with OpenMP (O2 + -fopenmp)
 *       and makes extensive use of loop‑unrolling and data locality
 *       to minimise cache misses.
 */
inline void convolveKernel(const std::vector<int>& imageIn,
                           std::vector<int>& imageOut,
                           size_t N)
{
    /*  Avoid rebuilding the kernel multiplier array each iteration.  */
    constexpr int k00 = edgeKernel[0][0];
    constexpr int k01 = edgeKernel[0][1];
    constexpr int k02 = edgeKernel[0][2];
    constexpr int k10 = edgeKernel[1][0];
    constexpr int k11 = edgeKernel[1][1];
    constexpr int k12 = edgeKernel[1][2];
    constexpr int k20 = edgeKernel[2][0];
    constexpr int k21 = edgeKernel[2][1];
    constexpr int k22 = edgeKernel[2][2];

    /*  Parallelise over rows and columns using static scheduling.  */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        for (size_t j = 0; j < N; ++j)
        {
            /*  Accumulate convolution result.  */
            int sum = 0;

            /*  Compute eight neighbours explicitly for speed.  */
            size_t i0 = (i > 0)    ? i - 1 : SIZE_MAX;
            size_t i1 = i;
            size_t i2 = (i + 1 < N) ? i + 1 : SIZE_MAX;

            size_t j0 = (j > 0)    ? j - 1 : SIZE_MAX;
            size_t j1 = j;
            size_t j2 = (j + 1 < N) ? j + 1 : SIZE_MAX;

            /*  Top row */
            if (i0 != SIZE_MAX) {
                if (j0 != SIZE_MAX) sum += imageIn[i0 * N + j0] * k00;
                sum          += imageIn[i0 * N + j1] * k01;
                if (j2 != SIZE_MAX) sum += imageIn[i0 * N + j2] * k02;
            }

            /*  Middle row */
            if (j0 != SIZE_MAX) sum += imageIn[i1 * N + j0] * k10;
            sum          += imageIn[i1 * N + j1] * k11;
            if (j2 != SIZE_MAX) sum += imageIn[i1 * N + j2] * k12;

            /*  Bottom row */
            if (i2 != SIZE_MAX) {
                if (j0 != SIZE_MAX) sum += imageIn[i2 * N + j0] * k20;
                sum          += imageIn[i2 * N + j1] * k21;
                if (j2 != SIZE_MAX) sum += imageIn[i2 * N + j2] * k22;
            }

            /*  Clip to [0,255] – identical to the reference.  */
            imageOut[i * N + j] = static_cast<int>(std::clamp(sum, 0, 255));
        }
    }
}
