#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <limits>
#include <cstddef>

struct Point {
    double x, y;
};

// distance between two points
inline double dist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

// variant that returns squared distance – used for speed
inline double dist2(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// merge helper used by the divide‑and‑conquer algorithm
static void inplace_merge_by_y(std::vector<Point>& pts,
                               std::vector<Point>& temp,
                               size_t l, size_t m, size_t r) {
    size_t i = l, j = m, k = l;
    while (i < m && j < r) {
        if (pts[i].y < pts[j].y)
            temp[k++] = pts[i++];
        else
            temp[k++] = pts[j++];
    }
    while (i < m) temp[k++] = pts[i++];
    while (j < r) temp[k++] = pts[j++];
    for (size_t idx = l; idx < r; ++idx)
        pts[idx] = temp[idx];
}

// recursive helper that returns the minimal squared distance
static double closest_pair_rec(std::vector<Point>& pts,
                               std::vector<Point>& temp,
                               size_t l, size_t r) {
    if (r - l <= 3) {                 // brute force
        double best = std::numeric_limits<double>::infinity();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j)
                best = std::min(best, dist2(pts[i], pts[j]));
        // sort by y for the merging step
        std::sort(pts.begin() + l, pts.begin() + r,
                  [](const Point& a, const Point& b){ return a.y < b.y; });
        return best;
    }

    size_t m = (l + r) >> 1;
    double mid_x = pts[m].x;
    double dl = closest_pair_rec(pts, temp, l, m);
    double dr = closest_pair_rec(pts, temp, m, r);
    double d = std::min(dl, dr);

    // Merge by y-coordinate
    inplace_merge_by_y(pts, temp, l, m, r);

    // Build strip of points whose x distance from mid line < sqrt(d)
    std::vector<Point> strip;
    strip.reserve(r - l);
    double d_sqrt = std::sqrt(d);
    for (size_t i = l; i < r; ++i)
        if (std::abs(pts[i].x - mid_x) < d_sqrt)
            strip.push_back(pts[i]);

    // Scan strip – at most 7 comparisons per point
    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1; j < strip.size() && 
             (strip[j].y - strip[i].y) < d_sqrt; ++j) {
            d = std::min(d, dist2(strip[i], strip[j]));
        }
    }

    return d;
}

double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2)
        return 0.0;

    // Copy and sort by x
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> temp(n);
    double minDist2 = closest_pair_rec(pts, temp, 0, n);
    return std::sqrt(minDist2);
}
```
This implementation follows the optimal \(O(n\log n)\) divide‑and‑conquer strategy, uses only integer and floating‑point operations that are amenable to vectorisation, and preserves the exact behaviour of the original code.

