inline void gameOfLife(const std::vector<int> &input,
                      std::vector<int> &output,
                      size_t N) {
    // Parallelize the outer loop with static scheduling
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t idx   = i * N;                     // start of row i
        const size_t idxPm = (i > 0) ? idx - N : SIZE_MAX;  // row i-1
        const size_t idxPmP = (i + 1 < N) ? idx + N : SIZE_MAX; // row i+1

        for (size_t j = 0; j < N; ++j) {
            int sum = 0;

            // vertical neighbours
            if (idxPm  != SIZE_MAX) sum += input[idxPm  + j];
            if (idxPmP != SIZE_MAX) sum += input[idxPmP + j];

            // horizontal neighbours
            if (j > 0)               sum += input[idx + j - 1];
            if (j + 1 < N)           sum += input[idx + j + 1];

            // diagonal neighbours
            if ((idxPm  != SIZE_MAX) && (j > 0))     sum += input[idxPm  + j - 1];
            if ((idxPm  != SIZE_MAX) && (j + 1 < N)) sum += input[idxPm  + j + 1];
            if ((idxPmP != SIZE_MAX) && (j > 0))     sum += input[idxPmP + j - 1];
            if ((idxPmP != SIZE_MAX) && (j + 1 < N)) sum += input[idxPmP + j + 1];

            const int cur = input[idx + j];
            // The new state: alive if exactly 3 neighbours,
            // or if currently alive and 2 neighbours
            output[idx + j] = (sum == 3 || (cur && sum == 2)) ? 1 : 0;
        }
    }
}
