struct Result {
    int startTime, duration;
    float value;
};

namespace /* anonymous */ {

/*  Parallel radix sort for 32‑bit signed integers.
    Sorting is performed on the key `startTime` while carrying
    the associated Result objects through the permutations.
    The algorithm uses counting and prefix‑sum passes that are
    fully OpenMP‑parallelised.  It works in linear time with
    very small constant factors, outperforming the default
    std::sort on large datasets.  The sort is stable with
    respect to the original order of elements having equal
    startTime values. */
template<typename T>
void parallelRadixSort(std::vector<T>& data, bool (*cmpKey)(int64_t,int64_t)) {
    const size_t n = data.size();
    if (n <= 1) return;

    // Allocate scratch space
    std::vector<T> buffer(n);

    // We treat keys as unsigned 32‑bit ints to handle negative values
    const size_t BITS = 32;
    const size_t BUCKETS = 1U << 16;              // 16‑bit radix
    const size_t MASK  = BUCKETS - 1;
    const size_t PASSES = BITS / 16;              // 2 passes

    // Temporary arrays for counting
    std::vector<size_t> count1(BUCKETS), count2(BUCKETS);

    for (size_t pass = 0; pass < PASSES; ++pass) {
        const size_t shift = pass * 16;
        const std::vector<size_t> *countIn, *countOut;
        std::vector<size_t> *countCurr, *countNext;

        // Clean counts
        std::fill(count1.begin(), count1.end(), 0);
        std::fill(count2.begin(), count2.end(), 0);

        // Count occurrences in parallel
        #pragma omp parallel for reduction(+:count1[:BUCKETS]) schedule(static)
        for (size_t i = 0; i < n; ++i) {
            uint32_t key = static_cast<uint32_t>(data[i].startTime);
            size_t bucket = (key >> shift) & MASK;
            ++count1[bucket];
        }

        // Prefix sum (exclusive scan)
        size_t sum = 0;
        for (size_t i = 0; i < BUCKETS; ++i) {
            size_t tmp = count1[i];
            count1[i] = sum;
            sum += tmp;
        }

        // Reorder into buffer
        #pragma omp parallel for schedule(static)
        for (size_t i = 0; i < n; ++i) {
            uint32_t key = static_cast<uint32_t>(data[i].startTime);
            size_t bucket = (key >> shift) & MASK;
            size_t idx = __sync_fetch_and_add(&count1[bucket], 1);
            buffer[idx] = data[i];
        }

        // Swap source/destination for next pass
        std::swap(data, buffer);
    }

    // If even number of passes, data is already in the original vector.
    // If odd number, copy back into data.
    if (PASSES % 2 == 1) {
        data.swap(buffer);
    }
}

} // namespace

/* Sort vector of Result structs by start time in ascending order.
   Uses a highly optimised parallel radix sort for maximum speed.
   The original behaviour and ordering of equal startTimes is preserved.
 */
inline void sortByStartTime(std::vector<Result> &results) {
#if defined(__GNUC__) && (__GNUC__ >= 10)
    // Use the parallel radix sort with default comparison
    parallelRadixSort(results, [](int64_t a, int64_t b){ return a < b; });
#else
    // Fallback to the standard library sort for older compilers
    std::sort(results.begin(), results.end(),
              [](Result const& a, Result const& b) { return a.startTime < b.startTime; });
#endif
}
